public async Task HandleConcurrentTicketPurchasesAsync(int numberOfTickets)
{
    // Validate input parameters
    if (numberOfTickets <= 0)
        throw new ArgumentException("Number of tickets must be greater than zero", nameof(numberOfTickets));

    // Check available seats in inventory
    var availableSeats = await _context.Inventory.FirstOrDefaultAsync(i => i.EventId == eventId && i.Available > 0);

    if (availableSeats == null || availableSeats.Available < numberOfTickets)
        throw new Exception("Not enough seats available");

    // Update inventory and validate purchase quantity
    var updatedInventory = await _context.Inventory.FindAsync(eventId);
    if (updatedInventory != null)
    {
        updatedInventory.Available -= numberOfTickets;
        await _context.SaveChangesAsync();

        if (updatedInventory.Available < 0)
            throw new Exception("Invalid purchase quantity");
    }
}